import pvlib
import pandas as pd
import numpy as np

print("Testing edge cases for temperature.fuentes")

# Test 1: Different time frequencies
print("\n1. Testing different time frequencies:")
for freq in ['h', '30min', '15min', '5min', '1min']:
    index = pd.date_range('2019-01-01', freq=freq, periods=3)
    kwargs = {
        'poa_global': pd.Series(1000, index=index),
        'temp_air': pd.Series(20, index=index),
        'wind_speed': pd.Series(1, index=index),
        'noct_installed': 45
    }
    try:
        result = pvlib.temperature.fuentes(**kwargs)
        print(f"  {freq}: Success, shape={result.shape}")
    except Exception as e:
        print(f"  {freq}: Error - {type(e).__name__}: {e}")

# Test 2: Different timezones
print("\n2. Testing different timezones:")
index = pd.date_range('2019-01-01', freq='h', periods=3)
for tz in ['UTC', 'US/Eastern', 'Asia/Tokyo', None]:
    kwargs = {
        'poa_global': pd.Series(1000, index=index),
        'temp_air': pd.Series(20, index=index),
        'wind_speed': pd.Series(1, index=index),
        'noct_installed': 45
    }
    if tz:
        kwargs['poa_global'].index = index.tz_localize(tz)
    try:
        result = pvlib.temperature.fuentes(**kwargs)
        print(f"  {tz}: Success, values={result.values[:2]}")
    except Exception as e:
        print(f"  {tz}: Error - {type(e).__name__}: {e}")

# Test 3: Irregular timestamps (not evenly spaced)
print("\n3. Testing irregular timestamps:")
times = pd.DatetimeIndex([
    '2019-01-01 00:00:00',
    '2019-01-01 01:30:00',  # 1.5 hours later
    '2019-01-01 03:00:00',  # 1.5 hours later
])
kwargs = {
    'poa_global': pd.Series([1000, 800, 600], index=times),
    'temp_air': pd.Series([20, 22, 24], index=times),
    'wind_speed': pd.Series([1, 2, 3], index=times),
    'noct_installed': 45
}
try:
    result = pvlib.temperature.fuentes(**kwargs)
    print(f"  Irregular: Success, values={result.values}")
except Exception as e:
    print(f"  Irregular: Error - {type(e).__name__}: {e}")

# Test 4: Single timestamp (should fail because diff needs at least 2)
print("\n4. Testing single timestamp:")
index = pd.date_range('2019-01-01', freq='h', periods=1)
kwargs = {
    'poa_global': pd.Series(1000, index=index),
    'temp_air': pd.Series(20, index=index),
    'wind_speed': pd.Series(1, index=index),
    'noct_installed': 45
}
try:
    result = pvlib.temperature.fuentes(**kwargs)
    print(f"  Single: Success, value={result.values}")
except Exception as e:
    print(f"  Single: Error - {type(e).__name__}: {e}")
EOF"}

